const fs=require('fs');
const s=fs.readFileSync('site/scrum/index.html','utf8');
// Tag balance check (rough): ignore self-closing/void tags
const voids=new Set(['area','base','br','col','embed','hr','img','input','link','meta','param','source','track','wbr']);
const re=/<\/?([a-zA-Z][a-zA-Z0-9]*)\b[^>]*?>/g;
const stack=[];let m,bad=null;
while((m=re.exec(s))){
  const full=m[0];const name=m[1].toLowerCase();
  if(full.startsWith('</')){
    const top=stack.pop();
    if(top!==name){bad={top,name,at:m.index};break;}
  } else if(!voids.has(name) && !full.endsWith('/>')) {
    stack.push(name);
  }
}
console.log('balanced:',!bad && stack.length===0,'remaining:',stack.length, bad||'');
// anchor targets exist
const anchors=[...s.matchAll(/href=\"#([^\"]+)\"/g)].map(x=>x[1]);
const ids=new Set([...s.matchAll(/id=\"([^\"]+)\"/g)].map(x=>x[1]));
const missing=anchors.filter(a=>a!=='top'?!ids.has(a):!ids.has('top'));
console.log('anchors:',anchors.length,'missing targets:',missing);
"
